1	/**
2	 * Checkout state machine — coordinates the full checkout/check-in lifecycle.
3	 * This is the orchestrator: it calls damClient, fileOps, uploadQueue, and
4	 * chokidar to drive a checkout from start to finish.
5	 */
6	
7	import { shell } from "electron";
8	import chokidar, { FSWatcher } from "chokidar";
9	import { existsSync, statSync } from "fs";
10	import { join, dirname, basename } from "path";
11	import {
12	  resolveAssetPath,
13	  copyToWorkspace,
14	  writeCheckoutMeta,
15	  waitForFileStable,
16	  createSnapshot,
17	  checkoutDir,
18	} from "./fileOps";
19	import { sha256File } from "./hash";
20	import {
21	  startCheckout as apiStartCheckout,
22	  prepareCheckin as apiPrepareCheckin,
23	  discardCheckout as apiDiscard,
24	  getOpenCheckouts,
25	} from "./damClient";
26	import { enqueue } from "./uploadQueue";
27	import { getConfig } from "./config";
28	import { validateRoot } from "./rootValidator";
29	import {
30	  getSeafileHealth,
31	  resolveSeafileTarget,
32	  ensureHydrated,
33	  getSeafileObjId,
34	} from "./seafileAdapter";
35	import { log } from "./logger";
36	import type { CheckoutRecord, RootMapping, StorageProvider } from "@shared/types";
37	
38	// In-memory map of active checkouts: checkoutId → record
39	const active = new Map<string, CheckoutRecord>();
40	// File watchers keyed by checkoutId
41	const watchers = new Map<string, FSWatcher>();
42	
43	let changeListener: (() => void) | null = null;
44	
45	export function onCheckoutsChanged(cb: () => void): void {
46	  changeListener = cb;
47	}
48	
49	function notify(): void {
50	  changeListener?.();
51	}
52	
53	// ── Load from server on startup ───────────────────────────────────────────────
54	
55	export async function loadActiveCheckouts(): Promise<void> {
56	  try {
57	    const res = await getOpenCheckouts();
58	    const config = getConfig();
59	    for (const co of res.checkouts ?? []) {
60	      const assetInfo = (co as any).assets ?? {};
61	      const record: CheckoutRecord = {
62	        id: co.id,
63	        assetId: assetInfo.id ?? "",
64	        userId: "",
65	        deviceId: null,
66	        status: co.status as CheckoutRecord["status"],
67	        checkedOutAt: co.checked_out_at,
68	        checkedInAt: null,
69	        filename: assetInfo.filename ?? "",
70	        relativePath: assetInfo.relative_path ?? "",
71	        rootId: "",
72	        sourceHash: co.source_hash,
73	        sourceSize: co.source_size,
74	        workspacePath: join(
75	          checkoutDir(config.workspacePath, co.id),
76	          assetInfo.filename ?? "",
77	        ),
78	        snapshotPath: null,
79	        uploadProgress: null,
80	        errorMessage: null,
81	      };
82	      active.set(co.id, record);
83	      watchFile(co.id, record.workspacePath);
84	    }
85	    notify();
86	  } catch (e) {
87	    log.warn("Failed to load active checkouts from server:", e);
88	  }
89	}
90	
91	// ── Checkout ──────────────────────────────────────────────────────────────────
92	
93	export async function checkout(
94	  token: string,
95	  assetId?: string,
96	): Promise<{ checkoutId: string; workspacePath: string }> {
97	  const config = getConfig();
98	
99	  const res = await apiStartCheckout({
100	    token,
101	    asset_id: assetId,
102	    device_id: config.deviceId,
103	    helper_version: config.helperVersion,
104	    computer_id: config.deviceName,
105	  });
106	
107	  const { checkout_id, asset, root_mappings } = res;
108	
109	  // Merge server root_mappings with locally saved paths
110	  const localMappings = config.rootMappings;
111	  const mergedMappings: RootMapping[] = root_mappings.map((rm: any) => {
112	    const local = localMappings.find((l) => l.root_id === rm.root_id);
113	    return {
114	      root_id: rm.root_id,
115	      display_name: rm.display_name ?? rm.root_id,
116	      local_path: local?.local_path ?? rm.local_path ?? "",
117	      marker_verified: local?.marker_verified ?? false,
118	    };
119	  });
120	
121	  // Double-check each mapping's local path is still pointing at the right folder level
122	  for (const mapping of mergedMappings) {
123	    if (!mapping.local_path) continue;
124	    const vResult = validateRoot(mapping.local_path, mapping.root_id);
125	    if (!vResult.ok) {
126	      if (vResult.reason === "too_deep" || vResult.reason === "too_shallow") {
127	        // Auto-correct in memory for this checkout — user should fix in Settings
128	        log.warn(`Root path level mismatch for "${mapping.root_id}" — correcting to ${vResult.suggestedPath}`);
129	        mapping.local_path = vResult.suggestedPath;
130	      } else if (vResult.reason === "wrong_root_id") {
131	        throw new Error(
132	          `Folder mapping for "${mapping.root_id}" points to the wrong NAS root ("${vResult.actual}"). Please fix your folder mappings in Settings.`,
133	        );
134	      }
135	      // no_marker and forbidden are non-blocking here — resolveAssetPath will fail if path is truly wrong
136	    }
137	  }
138	
139	  const rootId = asset.relative_path.split("/")[0] ?? asset.relative_path.split("\\")[0];
140	  const preferred: StorageProvider = config.preferredProvider ?? "seafile";
141	
142	  const resolveSynologyPath = (): string => {
143	    try {
144	      return resolveAssetPath(rootId, asset.relative_path, mergedMappings);
145	    } catch {
146	      throw new Error(
147	        `No local path configured for this asset. Please set up your folder mappings in Settings.`,
148	      );
149	    }
150	  };
151	
152	  let sourcePath: string | null = null;
153	  let sourceProvider: StorageProvider = "synology";
154	  let seafileObjId: string | undefined;
155	
156	  if (preferred === "seafile") {
157	    const health = getSeafileHealth(config);
158	    if (health.available) {
159	      try {
160	        const target = resolveSeafileTarget(asset.relative_path, config);
161	        // Confirm the file is fully local (or trigger + wait for hydration)
162	        await ensureHydrated(target.localPath, {
163	          onProgress: (s) =>
164	            log.debug(`Hydrating ${target.localPath}: ${s.state} ${s.bytesDone ?? 0}B`),
165	        });
166	        sourcePath = target.localPath;
167	        sourceProvider = "seafile";
168	        seafileObjId =
169	          (await getSeafileObjId(target.mapping.libraryId, target.pathInLib, config)) ?? undefined;
170	      } catch (e) {
171	        if (!config.synologyFallbackAllowed) throw e;
172	        log.warn(`Seafile resolution failed, falling back to Synology: ${(e as Error).message}`);
173	      }
174	    } else if (!config.synologyFallbackAllowed) {
175	      throw new Error(
176	        "Seafile/SeaDrive is unavailable and fallback is not enabled for this account." +
177	          (health.detail ? `\n\n${health.detail}` : ""),
178	      );
179	    } else {
180	      log.warn(`Seafile unavailable (${health.detail ?? "unknown"}); falling back to Synology.`);
181	    }
182	  }
183	
184	  if (!sourcePath) {
185	    sourcePath = resolveSynologyPath();
186	    sourceProvider = "synology";
187	  }
188	
189	  if (!existsSync(sourcePath)) {
190	    throw new Error(
191	      `File not found locally: ${sourcePath}\n\nIt may not have synced yet. Check your Seafile or Synology Drive client.`,
192	    );
193	  }
194	
195	  const copied = await copyToWorkspace(
196	    sourcePath,
197	    checkout_id,
198	    asset.filename,
199	    config.workspacePath,
200	  );
201	
202	  const destDir = checkoutDir(config.workspacePath, checkout_id);
203	  writeCheckoutMeta(destDir, {
204	    checkout_id,
205	    asset_id: asset.asset_id,
206	    root_id: asset.relative_path.split("/")[0],
207	    relative_path: asset.relative_path,
208	    filename: asset.filename,
209	    checked_out_at: new Date().toISOString(),
210	    source_hash: asset.expected_hash ?? copied.hash,
211	    source_size: asset.expected_size ?? copied.size,
212	    dam_url: `${config.damUrl}/assets/${asset.asset_id}`,
213	    source_provider: sourceProvider,
214	    source_local_path: sourcePath,
215	    seafile_obj_id: seafileObjId,
216	  });
217	
218	  const record: CheckoutRecord = {
219	    id: checkout_id,
220	    assetId: asset.asset_id,
221	    userId: "",
222	    deviceId: config.deviceId,
223	    status: "active",
224	    checkedOutAt: new Date().toISOString(),
225	    checkedInAt: null,
226	    filename: asset.filename,
227	    relativePath: asset.relative_path,
228	    rootId: asset.relative_path.split("/")[0],
229	    sourceHash: asset.expected_hash ?? copied.hash,
230	    sourceSize: asset.expected_size ?? copied.size,
231	    workspacePath: copied.workspacePath,
232	    snapshotPath: null,
233	    sourceProvider,
234	    sourceLocalPath: sourcePath,
235	    seafileObjId,
236	    uploadProgress: null,
237	    errorMessage: null,
238	  };
239	
240	  active.set(checkout_id, record);
241	  watchFile(checkout_id, copied.workspacePath);
242	  notify();
243	
244	  if (res.open_after_checkout) {
245	    await shell.openPath(copied.workspacePath);
246	  }
247	
248	  return { checkoutId: checkout_id, workspacePath: copied.workspacePath };
249	}
250	
251	// ── Check-in ──────────────────────────────────────────────────────────────────
252	
253	export async function checkin(checkoutId: string): Promise<void> {
254	  const record = active.get(checkoutId);
255	  if (!record) throw new Error(`Checkout ${checkoutId} not found`);
256	
257	  const config = getConfig();
258	
259	  updateStatus(checkoutId, "checkin_queued");
260	
261	  if (!existsSync(record.workspacePath)) {
262	    throw new Error(`Workspace file missing: ${record.workspacePath}`);
263	  }
264	
265	  // Wait for file to stop saving
266	  await waitForFileStable(record.workspacePath);
267	
268	  // Snapshot
269	  const snap = await createSnapshot(
270	    record.workspacePath,
271	    checkoutId,
272	    record.filename,
273	    config.workspacePath,
274	  );
275	
276	  // Tell DAM we're about to upload
277	  const instructions = await apiPrepareCheckin({
278	    checkout_id: checkoutId,
279	    snapshot_hash: snap.hash,
280	    snapshot_size: snap.size,
281	  });
282	
283	  record.snapshotPath = snap.snapshotPath;
284	
285	  // Enqueue async upload
286	  enqueue({
287	    checkoutId,
288	    snapshotPath: snap.snapshotPath,
289	    uploadMethod: "synology_file_station",
290	    synologyUrl: instructions.upload_instructions.synology_url,
291	    synologyPort: instructions.upload_instructions.synology_port,
292	    relativePath: instructions.upload_instructions.relative_path,
293	    filename: instructions.upload_instructions.filename,
294	    tempSuffix: instructions.upload_instructions.temp_suffix,
295	    retryCount: 0,
296	    addedAt: Date.now(),
297	    sourceProvider: record.sourceProvider,
298	    seafileObjId: record.seafileObjId,
299	  });
300	
301	  updateStatus(checkoutId, "uploading");
302	  notify();
303	}
304	
305	// ── Discard ───────────────────────────────────────────────────────────────────
306	
307	export async function discard(checkoutId: string): Promise<void> {
308	  await apiDiscard(checkoutId);
309	  stopWatcher(checkoutId);
310	  active.delete(checkoutId);
311	  notify();
312	}
313	
314	// ── Reveal ────────────────────────────────────────────────────────────────────
315	
316	export function revealFile(checkoutId: string): void {
317	  const record = active.get(checkoutId);
318	  if (!record || !existsSync(record.workspacePath)) return;
319	  shell.showItemInFolder(record.workspacePath);
320	}
321	
322	export function openFile(checkoutId: string): void {
323	  const record = active.get(checkoutId);
324	  if (!record || !existsSync(record.workspacePath)) return;
325	  shell.openPath(record.workspacePath);
326	}
327	
328	// ── Accessors ─────────────────────────────────────────────────────────────────
329	
330	export function getActiveCheckouts(): CheckoutRecord[] {
331	  return Array.from(active.values());
332	}
333	
334	export function updateUploadProgress(checkoutId: string, percent: number): void {
335	  const record = active.get(checkoutId);
336	  if (!record) return;
337	  record.uploadProgress = percent;
338	  if (percent >= 100) {
339	    record.status = "complete";
340	    active.delete(checkoutId);
341	    stopWatcher(checkoutId);
342	  }
343	  notify();
344	}
345	
346	function updateStatus(checkoutId: string, status: CheckoutRecord["status"]): void {
347	  const record = active.get(checkoutId);
348	  if (!record) return;
349	  record.status = status;
350	  notify();
351	}
352	
353	// ── File watcher ──────────────────────────────────────────────────────────────
354	
355	function watchFile(checkoutId: string, filePath: string): void {
356	  if (!existsSync(filePath)) return;
357	  stopWatcher(checkoutId);
358	
359	  const watcher = chokidar.watch(filePath, {
360	    persistent: true,
361	    ignoreInitial: true,
362	    awaitWriteFinish: { stabilityThreshold: 2000, pollInterval: 300 },
363	  });
364	
365	  watcher.on("change", () => {
366	    const record = active.get(checkoutId);
367	    if (!record) return;
368	    log.debug(`File changed: ${filePath}`);
369	    notify();
370	  });
371	
372	  watcher.on("unlink", () => {
373	    const record = active.get(checkoutId);
374	    if (!record) return;
375	    record.errorMessage = "Workspace file was deleted.";
376	    updateStatus(checkoutId, "error");
377	  });
378	
379	  watchers.set(checkoutId, watcher);
380	}
381	
382	function stopWatcher(checkoutId: string): void {
383	  const w = watchers.get(checkoutId);
384	  if (w) {
385	    w.close();
386	    watchers.delete(checkoutId);
387	  }
388	}
