7	import { createHash } from "node:crypto";
8	import { open, stat } from "node:fs/promises";
9	import { logger } from "./logger.js";
10	
11	const CHUNK_SIZE = 65536; // 64KB
12	const HASH_VERSION = 1;
13	
14	export interface QuickHashResult {
15	  quick_hash: string;
16	  quick_hash_version: number;
17	}
