  autoUpdater.logger = log;
  autoUpdater.checkForUpdatesAndNotify().catch((e: unknown) => {
    log.debug("Auto-update check skipped:", (e as Error).message);
  });

  log.info(`POP DAM Helper v${HELPER_VERSION} started`);
});

