401	  // Synology internal stores that must never be traversed or written to.
402	  // These directories contain millions of opaque file objects; writing or searching
403	  // there causes catastrophic disk I/O (confirmed: grep -R here ran for 4+ days).
404	  const FORBIDDEN_PATH_SEGMENTS = ["@synologydrive", "@synologydrivesharesync", "@appdata", "@docker"];
405	
406	  for (const rm of rootMappings) {
407	    if (!rm.root_id || !rm.server_path) continue;
408	    // server_path may be absolute (e.g. /mnt/nas/mac/Decor) or relative (e.g. Decor)
409	    const rootPath = rm.server_path.startsWith("/")
410	      ? rm.server_path.replace(/\/+$/, "")
411	      : `${mountRoot}/${rm.server_path.replace(/^\/+/, "")}`;
412	    const markerPath = `${rootPath}/pop-root.json`;
413	
414	    // Safety guard: refuse to write into Synology internal data stores.
415	    const lowerPath = rootPath.toLowerCase();
416	    if (FORBIDDEN_PATH_SEGMENTS.some((seg) => lowerPath.includes("/" + seg))) {
417	      logger.error("Root marker: refusing to write to Synology internal directory — this path must never be traversed", {
418	        rootId: rm.root_id, path: rootPath,
419	      });
420	      markerStatuses[rm.root_id] = { ok: false, error: "forbidden_path", at: new Date().toISOString() };
421	      continue;
422	    }
423	
424	    try {
425	      const s = await stat(rootPath);
426	      if (!s.isDirectory()) {
