428	        markerStatuses[rm.root_id] = { ok: false, error: "not_a_directory", at: new Date().toISOString() };
429	        continue;
430	      }
431	    } catch {
432	      logger.warn("Root marker: path not accessible", { rootId: rm.root_id, path: rootPath });
433	      markerStatuses[rm.root_id] = { ok: false, error: "path_not_accessible", at: new Date().toISOString() };
434	      continue;
435	    }
436	
437	    // Skip if marker already correct
438	    try {
439	      const existing = JSON.parse(await readFile(markerPath, "utf-8"));
440	      if (existing.root_id === rm.root_id && existing.type === "pop-dam-root") {
441	        markerStatuses[rm.root_id] = { ok: true, method: "exists", at: new Date().toISOString() };
442	        continue;
443	      }
444	    } catch { /* not found or invalid — write it */ }
445	
446	    const marker = {
447	      type: "pop-dam-root",
448	      root_id: rm.root_id,
449	      company: "POP Creations",
450	      created_by: "POP DAM Bridge Agent",
451	      canonical_server_path: rm.server_path,
452	      do_not_move: true,
453	      schema_version: 1,
454	    };
