456	    // Try direct write first
457	    try {
458	      await writeFile(markerPath, JSON.stringify(marker, null, 2), "utf-8");
459	      logger.info("Root marker written (direct)", { rootId: rm.root_id, path: markerPath });
460	      markerStatuses[rm.root_id] = { ok: true, method: "direct", at: new Date().toISOString() };
461	      continue;
462	    } catch (directErr) {
463	      const code = (directErr as NodeJS.ErrnoException).code;
464	      logger.warn("Root marker: direct write failed — trying Docker fallback", {
465	        rootId: rm.root_id, path: markerPath, code,
466	      });
