481	          rootId: rm.root_id, error: (dockerErr as Error).message,
482	        });
483	        markerStatuses[rm.root_id] = { ok: false, error: `docker_write_failed:${(dockerErr as Error).message}`, at: new Date().toISOString() };
484	      }
