    } else if (server.verify_failed_at) {
      // Lock still held, but verification did not succeed before the deadline.
      rec.errorMessage =
        server.verify_error ??
        "The server could not confirm this file was received intact. The asset stays locked — contact an admin.";
      changed = true;
    }
    // else: still verifying — leave it as-is.
  }

  if (changed) notify();
}

