/**
 * Check-in receipt verifier.
 *
 * Seafile-sourced check-ins reach the NYC Synology via an extra hop
 * (designer → Seafile → Synology), so the helper's HTTP upload returning does
 * not prove the fully-synced file has landed intact. helper-api parks those
 * check-ins in 'verifying' (lock held) until this agent — running ON the
 * Synology — confirms the on-disk file is present, complete, and byte-identical
 * to what the helper uploaded.
 *
 * Runs opportunistically on each heartbeat. Each pass claims the pending
 * verifications, checks size then full SHA-256 of the real file under the NAS
 * mount, and reports the outcome. Files still syncing report 'not_ready' and are
 * retried on the next pass; the server holds the lock and flags any that blow
 * past their deadline.
 */

import { join } from "node:path";
import { stat } from "node:fs/promises";
import * as api from "./api-client.js";
import { computeFullHash } from "./hasher.js";
import { logger } from "./logger.js";

let running = false;

export async function verifyPendingCheckins(mountRoot: string): Promise<void> {
  if (running) return; // never overlap passes — a big file's hash can outlast a heartbeat
  running = true;
  try {
    const items = await api.claimCheckinVerifications();
    if (items.length === 0) return;
    logger.info("Check-in verification: claimed pending verifications", { count: items.length });

    const cleanRoot = mountRoot.replace(/\/+$/, "");

    for (const item of items) {
      try {
        if (!item.relative_path) {
          await api.reportCheckinVerification({
            checkout_id: item.checkout_id,
            outcome: "not_ready",
            detail: "Asset has no relative_path on record — cannot locate file",
          });
          continue;
        }
        if (!item.expected_hash || item.expected_size == null) {
          await api.reportCheckinVerification({
            checkout_id: item.checkout_id,
            outcome: "not_ready",
            detail: "No expected hash/size recorded for this check-in",
          });
          continue;
        }

        const absPath = join(cleanRoot, item.relative_path);

        let size: number;
        try {
          const s = await stat(absPath);
          size = s.size;
        } catch {
          // File not on disk yet — still syncing from Seafile.
          await api.reportCheckinVerification({
            checkout_id: item.checkout_id,
            outcome: "not_ready",
            detail: "File has not arrived on the Synology yet",
          });
          continue;
        }

        if (size !== item.expected_size) {
          // Present but wrong size — a partial/in-progress sync. Retry next pass.
          await api.reportCheckinVerification({
            checkout_id: item.checkout_id,
            outcome: "not_ready",
            detail: `Size ${size} of expected ${item.expected_size} bytes — still syncing`,
          });
          continue;
        }

        const fullHash = await computeFullHash(absPath);
        if (fullHash === item.expected_hash) {
          await api.reportCheckinVerification({
            checkout_id: item.checkout_id,
            outcome: "verified",
            final_hash: fullHash,
            final_size: size,
          });
          logger.info("Check-in verified — file received intact", {
            checkout_id: item.checkout_id,
            path: item.relative_path,
          });
        } else {
          // Right size, wrong bytes. Could be an in-place overwrite mid-sync;
          // report as mismatch — server retries until deadline, then flags it.
          await api.reportCheckinVerification({
            checkout_id: item.checkout_id,
            outcome: "mismatch",
            detail: "On-disk full hash does not match the uploaded file",
          });
          logger.warn("Check-in hash mismatch", {
            checkout_id: item.checkout_id,
            path: item.relative_path,
          });
        }
      } catch (e) {
        // Don't let one bad item abort the rest of the batch.
        logger.warn("Check-in verification: item failed (will retry next pass)", {
          checkout_id: item.checkout_id,
          error: (e as Error).message,
        });
        await api
          .reportCheckinVerification({
            checkout_id: item.checkout_id,
            outcome: "not_ready",
            detail: `Verification error: ${(e as Error).message}`.slice(0, 500),
          })
          .catch(() => {/* best-effort */});
      }
    }
  } catch (e) {
    logger.warn("Check-in verification pass failed", { error: (e as Error).message });
  } finally {
