/**
 * Full-content SHA-256 of a file, streamed so large PSD/AI files don't load
 * entirely into memory. Used to verify a checked-in file was received intact on
 * the Synology — must match the full SHA-256 the helper computed after upload.
 */
export async function computeFullHash(filePath: string): Promise<string> {
  const { createReadStream } = await import("node:fs");
  const hash = createHash("sha256");
  await new Promise<void>((resolve, reject) => {
    const stream = createReadStream(filePath);
    stream.on("data", (chunk) => hash.update(chunk));
    stream.on("end", () => resolve());
    stream.on("error", reject);
  });
  return hash.digest("hex");
}

