    .from("admin_config")
    .select("value")
    .eq("key", "CHECKIN_VERIFICATION_ENABLED")
    .maybeSingle();
  const v = data?.value as unknown;
  return v === true || v === "true" || (typeof v === "object" && v !== null && (v as { enabled?: boolean }).enabled === true);
}

